import React, { useState } from 'react';
import { navigateToUrl } from 'single-spa';
import { useAppDispatch } from '../../store/hooks';
import { addQuickLink, removeQuickLink } from '../../store/slices/quickLinksSlice';
import type { QuickLink } from '../../services/quickLinksService';
import styles from './DashboardPage.module.css';

interface Props {
  items: QuickLink[];
  loading: boolean;
}

const ICON_OPTIONS = [
  'fas fa-chart-line', 'fas fa-file-invoice', 'fas fa-users', 'fas fa-cog',
  'fas fa-box', 'fas fa-truck', 'fas fa-wallet', 'fas fa-building',
  'fas fa-clipboard-list', 'fas fa-star',
];

const COLOR_OPTIONS = [
  '#2563eb', '#7c3aed', '#059669', '#d97706',
  '#dc2626', '#0891b2', '#9333ea', '#16a34a',
];

interface AddLinkForm {
  label: string;
  path: string;
  icon: string;
  color: string;
}

const defaultForm: AddLinkForm = { label: '', path: '', icon: ICON_OPTIONS[0], color: COLOR_OPTIONS[0] };

const QuickLinkSection: React.FC<Props> = ({ items, loading }) => {
  const dispatch = useAppDispatch();
  const [showModal, setShowModal] = useState(false);
  const [form, setForm] = useState<AddLinkForm>(defaultForm);
  const [saving, setSaving] = useState(false);
  const [errors, setErrors] = useState<Partial<AddLinkForm>>({});

  const validate = (): boolean => {
    const e: Partial<AddLinkForm> = {};
    if (!form.label.trim()) e.label = 'Vui lòng nhập tên';
    if (!form.path.trim()) e.path = 'Vui lòng nhập đường dẫn';
    else if (!form.path.startsWith('/')) e.path = 'Đường dẫn phải bắt đầu bằng /';
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const handleAdd = async () => {
    if (!validate()) return;
    setSaving(true);
    await dispatch(addQuickLink({ label: form.label.trim(), path: form.path.trim(), icon: form.icon, color: form.color }));
    setSaving(false);
    setShowModal(false);
    setForm(defaultForm);
    setErrors({});
  };

  const handleClose = () => {
    setShowModal(false);
    setForm(defaultForm);
    setErrors({});
  };

  return (
    <section className={styles.section}>
      <div className={styles.sectionHeader}>
        <h2 className={styles.sectionTitle}>
          <i className="fas fa-star"></i> Lối tắt nhanh
        </h2>
        <button className={styles.addBtn} onClick={() => setShowModal(true)}>
          <i className="fas fa-plus"></i> Thêm lối tắt
        </button>
      </div>

      {loading && <div className={styles.loadingText}>Đang tải...</div>}

      {!loading && items.length === 0 && (
        <div className={styles.emptyState}>
          <i className="fas fa-star" style={{ fontSize: 32, color: '#d1d5db' }}></i>
          <p>Chưa có lối tắt nào. Nhấn <strong>Thêm lối tắt</strong> để bắt đầu.</p>
        </div>
      )}

      <div className={styles.quickLinkGrid}>
        {items.map((link) => (
          <div key={link.id} className={styles.quickLinkCard}>
            <button
              className={styles.quickLinkRemove}
              onClick={() => dispatch(removeQuickLink(link.id))}
              title="Xoá lối tắt"
            >
              <i className="fas fa-times"></i>
            </button>
            <button
              className={styles.quickLinkContent}
              onClick={() => navigateToUrl(link.path)}
            >
              <span className={styles.quickLinkIcon} style={{ background: link.color ?? '#2563eb' }}>
                <i className={link.icon}></i>
              </span>
              <span className={styles.quickLinkLabel}>{link.label}</span>
            </button>
          </div>
        ))}
      </div>

      {showModal && (
        <div className={styles.modalOverlay} onClick={handleClose}>
          <div className={styles.modal} onClick={(e) => e.stopPropagation()}>
            <div className={styles.modalHeader}>
              <h3>Thêm lối tắt</h3>
              <button className={styles.modalClose} onClick={handleClose}>
                <i className="fas fa-times"></i>
              </button>
            </div>

            <div className={styles.modalBody}>
              <div className={styles.field}>
                <label className={styles.label}>Tên hiển thị <span className={styles.required}>*</span></label>
                <input
                  className={`${styles.input} ${errors.label ? styles.inputError : ''}`}
                  value={form.label}
                  onChange={(e) => setForm((f) => ({ ...f, label: e.target.value }))}
                  placeholder="VD: Kế toán tổng hợp"
                  maxLength={50}
                />
                {errors.label && <span className={styles.errorMsg}>{errors.label}</span>}
              </div>

              <div className={styles.field}>
                <label className={styles.label}>Đường dẫn <span className={styles.required}>*</span></label>
                <input
                  className={`${styles.input} ${errors.path ? styles.inputError : ''}`}
                  value={form.path}
                  onChange={(e) => setForm((f) => ({ ...f, path: e.target.value }))}
                  placeholder="/erp/accounting"
                />
                {errors.path && <span className={styles.errorMsg}>{errors.path}</span>}
              </div>

              <div className={styles.field}>
                <label className={styles.label}>Icon</label>
                <div className={styles.iconGrid}>
                  {ICON_OPTIONS.map((ic) => (
                    <button
                      key={ic}
                      className={`${styles.iconOption} ${form.icon === ic ? styles.iconSelected : ''}`}
                      onClick={() => setForm((f) => ({ ...f, icon: ic }))}
                      title={ic}
                    >
                      <i className={ic}></i>
                    </button>
                  ))}
                </div>
              </div>

              <div className={styles.field}>
                <label className={styles.label}>Màu nền</label>
                <div className={styles.colorGrid}>
                  {COLOR_OPTIONS.map((c) => (
                    <button
                      key={c}
                      className={`${styles.colorOption} ${form.color === c ? styles.colorSelected : ''}`}
                      style={{ background: c }}
                      onClick={() => setForm((f) => ({ ...f, color: c }))}
                    />
                  ))}
                </div>
              </div>
            </div>

            <div className={styles.modalFooter}>
              <button className={styles.btnCancel} onClick={handleClose}>Huỷ</button>
              <button className={styles.btnSave} onClick={handleAdd} disabled={saving}>
                {saving ? <i className="fas fa-spinner fa-spin"></i> : 'Lưu'}
              </button>
            </div>
          </div>
        </div>
      )}
    </section>
  );
};

export default QuickLinkSection;
