import React, { useEffect } from 'react';
import { useNavTitle } from '@linm-soft/common-components';
import { useAppDispatch, useAppSelector } from '../../store/hooks';
import { fetchQuickLinks } from '../../store/slices/quickLinksSlice';
import QuickLinkSection from './QuickLinkSection';
import WidgetArea from './WidgetArea';
import styles from './DashboardPage.module.css';

const DashboardPage: React.FC = () => {
  useNavTitle('Bảng điều khiển');
  const dispatch = useAppDispatch();
  const { items, loading } = useAppSelector((s) => s.quickLinks);

  useEffect(() => {
    const t = setTimeout(() => { dispatch(fetchQuickLinks()); }, 0);
    return () => clearTimeout(t);
  }, [dispatch]);

  return (
    <div className={styles.page}>
      <header className={styles.header}>
        <h1 className={styles.title}>Dashboard</h1>
        <p className={styles.subtitle}>Tổng quan và lối tắt nhanh</p>
      </header>

      <QuickLinkSection items={items} loading={loading} />

      <WidgetArea />
    </div>
  );
};

export default DashboardPage;
